class Solution {
    public int minFlipsMonoIncr(String s) {
        int n = s.length();
        int result = 0;
        for (int i = 0; i < n; i++) {
            if (s.charAt(i) == '0' && s.charAt(i + 1) == '1') {
                result++;
            }
        }
        return result;
    }
}
